    public function fetch_markets($params = array ()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * retrieves data on all markets for bidarz, including spot and OTC markets
             * @see https://new-api.bidarz.ir/v1/arz-digital/spot/markets
             * @see https://new-api.bidarz.ir/v1/arz-digital/otc/markets
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} an array of objects representing $market data
             */
            $result = array();
            $spotResponse = Async\await($this->publicGetV1ArzDigitalSpotMarkets ($params));
            $spotData = $this->safe_dict($spotResponse, 'data', array());
            $spotSymbols = $this->safe_dict($spotData, 'symbols', array());
            $spotIds = is_array($spotSymbols) ? array_keys($spotSymbols) : array();
            for ($i = 0; $i < count($spotIds); $i++) {
                $market = $this->parse_market($spotSymbols[$spotIds[$i]], 'spot');
                $result[] = $market;
            }
            $otcResponse = Async\await($this->publicGetV1ArzDigitalOtcMarkets ($params));
            $otcData = $this->safe_dict($otcResponse, 'data', array());
            $otcSymbols = $this->safe_dict($otcData, 'symbols', array());
            $otcIds = is_array($otcSymbols) ? array_keys($otcSymbols) : array();
            for ($i = 0; $i < count($otcIds); $i++) {
                $market = $this->parse_market($otcSymbols[$otcIds[$i]], 'otc');
                $result[] = $market;
            }
            return $result;
        }) ();
    }

