    public function fetch_ticker(string $symbol, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $params) {
            /**
             * fetches a price $ticker, defaulting duplicate raw spot/OTC symbols to the spot market
             * @see https://new-api.bidarz.ir/v1/arz-digital/spot/markets
             * @param {string} $symbol unified $symbol of the market to fetch the $ticker for
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a ~@link https://docs.ccxt.com/#/?id=$ticker-structure $ticker structure~
             */
            $ticker = Async\await($this->fetch_tickers(array( $symbol ), $params));
            return $ticker[$symbol];
        }) ();
    }

    public function parse_ticker($ticker, ?array $market = null, $type = 'spot'): array {
        $isOtc = ($type === 'otc');
        $marketId = $this->safe_string($ticker, 'symbol');
        if ($isOtc) {
            $marketId .= ':OTC';
        }
        $symbol = $this->safe_symbol($marketId, $market);
        $last = $this->convert_price($this->safe_string($ticker, 'price'));
        $bid = $this->convert_price($this->safe_string($ticker, 'sellPrice'));
        $ask = $this->convert_price($this->safe_string($ticker, 'buyPrice'));
        $high = $this->convert_price($this->safe_string($ticker, 'maxPrice24h'));
        $low = $this->convert_price($this->safe_string($ticker, 'minPrice24h'));
        $open = $this->convert_price($this->safe_string($ticker, 'price24h'));
        $quoteVolume = $this->convert_price($this->safe_string($ticker, 'volume24h'));
        $close = $last;
        if ($isOtc) {
            $close = null;
        }
        return $this->safe_ticker(array(
            'symbol' => $symbol,
            'timestamp' => null,
            'datetime' => null,
            'high' => $high,
            'low' => $low,
            'bid' => $bid,
            'bidVolume' => null,
            'ask' => $ask,
            'askVolume' => null,
            'vwap' => null,
            'open' => $open,
            'close' => $close,
            'last' => $close,
            'previousClose' => null,
            'change' => null,
            'percentage' => null,
            'average' => null,
            'baseVolume' => null,
            'quoteVolume' => $quoteVolume,
            'info' => $ticker,
        ), $market);
    }

    public function convert_price($price) {
        $value = $this->parse_number($price);
        return ($value === null) ? null : $value / 10;
    }

    public function sign($path, $api = 'public', $method = 'GET', $params = array (), $headers = null, $body = null) {
        $query = $this->omit($params, $this->extract_params($path));
        $url = $this->urls['api'][$api] . '/' . $this->implode_params($path, $params);
        if ($query) {
            $url .= '?' . $this->urlencode($query);
        }
        $headers = array( 'Content-Type' => 'application/json' );
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }
